def validate_endpoint_url(url: str) -> tuple[bool, str]:
    """
    Validate that the provided URL is a safe, allowed webhook endpoint.
    Returns (is_valid, reason).
    """
    if not url or not isinstance(url, str):
        return False, "Endpoint URL is empty or not a string."

    url = url.strip()

    # Parse the URL
    try:
        parsed = urlparse(url)
    except Exception:
        return False, "Failed to parse URL."

    # Enforce HTTPS only
    if parsed.scheme not in ALLOWED_PROTOCOLS:
        return False, f"Protocol '{parsed.scheme}' is not allowed. Only HTTPS is permitted."

    # Ensure hostname is present
    hostname = parsed.hostname
    if not hostname:
        return False, "URL must contain a valid hostname."

    # Block IP-based URLs to prevent SSRF
    for pattern in BLOCKED_IP_PATTERNS:
        if re.search(pattern, hostname, re.IGNORECASE):
            return False, f"IP-based or internal network URLs are not allowed: {hostname}"

    # Check against allowlist of domains
    domain_allowed = False
    for allowed_domain in ALLOWED_DOMAINS:
        if hostname == allowed_domain or hostname.endswith(f".{allowed_domain}"):
            domain_allowed = True
            break

    if not domain_allowed:
        return False, (
            f"Domain '{hostname}' is not in the allowed domains list. "
            f"Allowed: {ALLOWED_DOMAINS}"
        )

    # Validate URL doesn't contain suspicious characters (injection prevention)
    if re.search(r'[\x00-\x1f\x7f<>{}|\\^`]', url):
        return False, "URL contains invalid or suspicious characters."

    # Ensure path doesn't contain directory traversal
    if ".." in parsed.path:
        return False, "URL path contains directory traversal patterns."

    # Ensure reasonable URL length
    if len(url) > 2048:
        return False, "URL exceeds maximum allowed length (2048 characters)."

    return True, "Valid"


def get_or_validate_topic_arn(sns_client, topic_arn: str) -> bool:
    """Verify that the topic ARN exists and is accessible."""
    try:
        sns_client.get_topic_attributes(TopicArn=topic_arn)
        return True
    except ClientError as e:
        logger.error("Topic ARN validation failed: %s", e.response['Error']['Message'])
        return False


def create_sns_subscription(topic_arn: str, endpoint_url: str, filter_policy: dict = None) -> dict | None:
    """
    Create an SNS subscription with validated inputs and security controls.
    """
    # Validate endpoint URL
    is_valid, reason = validate_endpoint_url(endpoint_url)
    if not is_valid:
        logger.error("Endpoint validation failed: %s (input: %s)", reason, endpoint_url)
        raise ValueError(f"Invalid endpoint URL: {reason}")

    # Validate topic ARN format
    if not re.match(r'^arn:aws:sns:[a-z0-9-]+:\d{12}:[a-zA-Z0-9_-]+$', topic_arn):
        raise ValueError(f"Invalid SNS Topic ARN format: {topic_arn}")

    try:
        sns_client = boto3.client('sns')

        # Verify topic exists
        if not get_or_validate_topic_arn(sns_client, topic_arn):
            raise ValueError(f"Topic ARN does not exist or is not accessible: {topic_arn}")

        # Create subscription with HTTPS only
        subscribe_params = {
            'TopicArn': topic_arn,
            'Protocol': 'https',
            'Endpoint': endpoint_url,
            'ReturnSubscriptionArn': True,
        }

        response = sns_client.subscribe(**subscribe_params)
        subscription_arn = response.get('SubscriptionArn', '')

        logger.info(
            "Subscription created successfully. ARN: %s, Endpoint: %s",
            subscription_arn, endpoint_url
        )

        # Optionally set a filter policy to limit message delivery
        if filter_policy and subscription_arn and subscription_arn != 'pending confirmation':
            sns_client.set_subscription_attributes(
                SubscriptionArn=subscription_arn,
                AttributeName='FilterPolicy',
                AttributeValue=str(filter_policy),
            )
            logger.info("Filter policy applied to subscription: %s", subscription_arn)

        # Enable raw message delivery if desired (reduces wrapping overhead)
        if subscription_arn and subscription_arn != 'pending confirmation':
            sns_client.set_subscription_attributes(
                SubscriptionArn=subscription_arn,
                AttributeName='RawMessageDelivery',
                AttributeValue='false',  # Keep SNS envelope for signature verification
            )

        return response

    except ClientError as e:
        logger.error("AWS API error creating subscription: %s", e.response['Error']['Message'])
        raise
    except BotoCoreError as e:
        logger.error("Boto3 error creating subscription: %s", str(e))
        raise


def list_subscriptions_for_topic(topic_arn: str) -> list:
    """List all subscriptions for a given topic."""
    sns_client = boto3.client('sns')
    subscriptions = []

    try:
        paginator = sns_client.get_paginator('list_subscriptions_by_topic')
        for page in paginator.paginate(TopicArn=topic_arn):
            subscriptions.extend(page.get('Subscriptions', []))
    except ClientError as e:
        logger.error("Error listing subscriptions: %s", e.response['Error']['Message'])
        raise

    return subscriptions


def unsubscribe(subscription_arn: str) -> None:
    """Remove an SNS subscription."""
    if not re.match(r'^arn:aws:sns:[a-z0-9-]+:\d{12}:[a-zA-Z0-9_-]+:[a-f0-9-]+$', subscription_arn):
        raise ValueError(f"Invalid subscription ARN format: {subscription_arn}")

    sns_client = boto3.client('sns')
    try:
        sns_client.unsubscribe(SubscriptionArn=subscription_arn)
        logger.info("Successfully unsubscribed: %s", subscription_arn)
    except ClientError as e:
        logger.error("Error unsubscribing: %s", e.response['Error']['Message'])
        raise


